// Declaration inside class
class MyClass {
public:
 static int count; // Declaration only
 static const int MAX = 100; // C++11 in-class init

 MyClass() {
 count++; // Increment when object created
 }
};

// Definition outside class (required)
int MyClass::count = 0;

int main() {
 MyClass obj1, obj2, obj3;
 cout << MyClass::count; // Output: 3
 return 0;
}

class Counter {
private:
 static int count;
 int value;

public:
 Counter(int v = 0) : value(v) {
 count++;
 }

 // Static member function
 static int getCount() {
 // value++; // ERROR: cannot access non-static
 // this; // ERROR: no 'this' pointer
 return count; // OK: can access static members
 }

 // Non-static function can access both
 void display() {
 cout << "Value: " << value << ", Count: " << count;
 }
};

int Counter::count = 0;

int main() {
 Counter c1(10), c2(20);
 cout << Counter::getCount(); // 2
 cout << c1.getCount(); // 2 (also works)
 return 0;
}

class ObjectCounter {
private:
 static int objectCount;
 int id;

public:
 ObjectCounter() {
 id = ++objectCount;
 }

 ~ObjectCounter() {
 objectCount--;
 }

 static int getObjectCount() {
 return objectCount;
 }

 void display() {
 cout << "Object ID: " << id << endl;
 }
};

int ObjectCounter::objectCount = 0;

int main() {
 cout << "Initial count: " << ObjectCounter::getObjectCount();

 {
 ObjectCounter obj1;
 ObjectCounter obj2;
 cout << "After creating 2: " << ObjectCounter::getObjectCount();
 }

 cout << "After scope: " << ObjectCounter::getObjectCount();
 return 0;
}

// Output:
// Initial count: 0
// After creating 2: 2
// After scope: 0

#include <iostream>
using namespace std;

void test() {
 static int staticVar = 0; // Initialized only once
 int normalVar = 0; // Initialized every call

 staticVar++;
 normalVar++;

 cout << "Static: " << staticVar << ", Normal: " << normalVar;
}

int main() {
 test(); // Static: 1, Normal: 1
 test(); // Static: 2, Normal: 1
 test(); // Static: 3, Normal: 1
 return 0;
}

// Output:
// Static: 1, Normal: 1
// Static: 2, Normal: 1
// Static: 3, Normal: 1
